/**
* Remove the interval calls.
*/
declare function clearInterval(timeout: Timeout): void

/**
* Cancels the timeout.
*/
declare function clearTimeout(timeout: Timeout): void

/**
* Dynamically creates a function object from a string of JavaScript code. This allows you to generate and execute functions at runtime.
*/
declare function createFunctionObject(code: string, funcName: string): any

/**
* Repeatedly call `callback` every `delayMs` milliseconds.
*/
declare function setInterval(callback: () => void, delayMs: number): Timeout

/**
* Call `callback` after `delayMs` milliseconds.
*/
declare function setTimeout(callback: () => void, delayMs: number): Timeout

declare namespace global {
    /**
    * Provides access to the plugin's {@link SecureLocalStorage}.
    */
    let secureLocalStorage: SecureLocalStorage
    
}

/**
* Utility class for encoding and decoding data in base64 format.

* @example
* ```ts
*     // Encode a string to base64
*     const encoded = Base64.encodeString('Hello, Lens Studio!');
*     console.log('Encoded:', encoded);

*     // Decode base64 back to bytes
*     const decoded = Base64.decode(encoded);
*     const text = new TextDecoder().decode(decoded);
*     console.log('Decoded text:', text);

*     // Round-trip binary data through base64
*     const original = new Uint8Array([72, 101, 108, 108, 111]);
*     const b64 = Base64.encode(original);
*     const restored = Base64.decode(b64);
*     console.log('Round-trip match:', original.every((v, i) => v === restored[i]));
* ```

*/
declare class Base64 {
    
    /** @hidden */
    protected constructor()
    
    /**
    * Decode a base64 string to a Uint8Array.
    */
    static decode(value: string): Uint8Array
    
    /**
    * Encode a Uint8Array to a base64 string.
    */
    static encode(data: Uint8Array): string
    
    /**
    * Encode a string to a base64 string.
    */
    static encodeString(str: string): string
    
}

/**
* Base class for plugin descriptors containing metadata and interface requirements.

* @example
* ```ts
*     // BaseDescriptor fields: id, name, description, dependencies, interfaces
*     const desc = new Descriptor();
*     desc.id = 'com.example.my-plugin';
*     desc.name = 'My Plugin';
*     desc.description = 'A sample plugin demonstrating BaseDescriptor fields';
*     desc.dependencies = [Editor.Model.IModel];
*     desc.interfaces = [];

*     console.log(`Descriptor "${desc.name}" (${desc.id}): ${desc.dependencies.length} dependency(ies), ${desc.interfaces.length} interface(s)`);
* ```

*/
declare class BaseDescriptor extends IPluginDescriptor {
    
    /** @hidden */
    protected constructor()
    
    /**
    * Array of interface IDs that this plugin requires to function.
    */
    dependencies: Editor.InterfaceId[]
    
    /**
    * Human-readable description of the plugin shown in the plugin manager.
    */
    description: string
    
    /**
    * Unique identifier for the plugin, typically in reverse domain notation.
    */
    id: string
    
    /**
    * Array of target platforms (Snapchat, Spectacles) where this plugin is intended to run.
    
    */
    intendedPlatforms: Editor.TargetPlatform[]
    
    /**
    * Array of interface IDs that this plugin provides or implements.
    */
    interfaces: Editor.InterfaceId[]
    
    /**
    * Display name of the plugin.
    */
    name: string
    
}

/**
* Output logging utilities for plugin scripts.

* @example
* ```ts
*     // Standard log levels
*     console.log('Plugin started successfully');
*     console.info('Editor version info logged at info level');
*     console.warn('This API is deprecated — use the newer version');

*     // console.None suppresses output from appearing in the Logger panel
*     console.log('Internal-only message', (console as any).None);
* ```

*/
declare class console {
    
    /** @hidden */
    protected constructor()
    
    /**
    * Log debug-level messages.
    */
    static debug(...data: any[]): void
    
    /**
    * Log error-level messages.
    */
    static error(...data: any[]): void
    
    /**
    * Log info-level messages.
    */
    static info(...data: any[]): void
    
    /**
    * Log general messages.
    */
    static log(...data: any[]): void
    
    /**
    * Log stack trace.
    */
    static trace(...data: any[]): void
    
    /**
    * Log warning-level messages.
    */
    static warn(...data: any[]): void
    
    /**
    * Console.Category passed as the trailing argument to console.log/warn/error to suppress display in the developer console while keeping the entry in retrievable log files.
    
    */
    static None: console.Category
    
    /**
    * Console.Category for user-facing log entries shown in the developer console.
    
    */
    static User: console.Category
    
}

declare namespace console {
    /**
    * Enum-like type for log categories (console.None, console.User).
    
    * @example
    * ```ts
    *     // console.Category controls where log messages appear.
    *     // console.User (default) — message appears in the Logger panel.
    *     // console.None — message goes to internal log only, hidden from Logger panel.
    
    *     // Pass the category as the last argument to console.log / console.warn:
    *     const con = console as any;
    *     console.log('This appears in the Logger panel', con.User);
    *     console.log('This is internal only — hidden from Logger panel', con.None);
    
    *     console.warn('Visible warning', con.User);
    *     console.warn('Internal-only warning', con.None);
    * ```
    
    */
    class Category {
        
        /** @hidden */
        protected constructor()
        
    }

}

