declare namespace Editor {
    namespace Assets {
        /**
        * How a texture should be sampled. 
        
        * @example
        * ```ts
        *     const model = this.pluginSystem.findInterface(Editor.Model.IModel) as Editor.Model.IModel;
        *     const assetManager = model.project.assetManager;
        
        *     // FilteringMode controls texture sampling quality via Sampler
        *     // Create a TextureParameter referencing a texture, then configure its sampler
        *     const textures = assetManager.assets.filter(a => a.isOfType('Texture'));
        *     if (textures.length === 0) {
        *       console.log('No textures in project');
        *       return;
        *     }
        
        *     const texParam = new Editor.Assets.TextureParameter(textures[0].id);
        *     const sampler = texParam.sampler;
        
        *     // Nearest: no interpolation (pixel art, UI sprites)
        *     sampler.filteringMode = Editor.Assets.FilteringMode.Nearest;
        
        *     // Bilinear: smooth interpolation between adjacent texels
        *     sampler.filteringMode = Editor.Assets.FilteringMode.Bilinear;
        
        *     // Trilinear: bilinear + mipmap interpolation
        *     sampler.filteringMode = Editor.Assets.FilteringMode.Trilinear;
        
        *     console.log(`Final filteringMode: Trilinear (${sampler.filteringMode})`);
        * ```
        
        */
        enum FilteringMode {
            /**
            * Point sampling with no interpolation.
            */
            Nearest,
            /**
            * Linear interpolation between adjacent pixels.
            */
            Bilinear,
            /**
            * Linear interpolation with mipmap support.
            */
            Trilinear
        }
    
    }

}

