declare namespace Editor {
    namespace Assets {
        /**
        * Enum defining types of bindings for render passes.
        
        * @example
        * ```ts
        *     const model = this.pluginSystem.findInterface(Editor.Model.IModel) as Editor.Model.IModel;
        *     const assetManager = model.project.assetManager;
        *     const materials = assetManager.assets.filter(
        *       a => a.isOfType('Material')
        *     ) as Editor.Assets.Material[];
        
        *     // PassBindingType discriminates Property (shader uniforms) vs Define (compile-time switches)
        *     let propertyCount = 0;
        *     let defineCount = 0;
        *     for (const mat of materials) {
        *       const passes = mat.passInfos;
        *       if (passes.length === 0) continue;
        *       const uiData = passes[0].uiData;
        *       for (const binding of uiData.passBindings) {
        *         if (binding.type === Editor.Assets.PassBindingType.Property) propertyCount++;
        *         else if (binding.type === Editor.Assets.PassBindingType.Define) defineCount++;
        *       }
        *     }
        
        *     console.log(`Across ${materials.length} material(s): ${propertyCount} Property binding(s), ${defineCount} Define binding(s)`);
        * ```
        
        */
        enum PassBindingType {
            /**
            * Invalid or uninitialized binding type.
            */
            Invalid,
            /**
            * Binding to a material property.
            */
            Property,
            /**
            * Binding to a shader define.
            */
            Define,
            /**
            * Binding to a define with selectable options.
            */
            DefineSelect,
            /**
            * Binding to a specific value within a define select.
            */
            DefineSelectValue,
            /**
            * Marks the end of a binding group.
            */
            GroupEnd
        }
    
    }

}

