declare namespace Editor {
    namespace Assets {
        /**
        * Used witih {@link Editor.Assets.FaceMesh}
        
        * @example
        * ```ts
        *     const attrs = [
        *       { name: 'Position',  value: Editor.Assets.VertexAttribute.Position },
        *       { name: 'Normal',    value: Editor.Assets.VertexAttribute.Normal },
        *       { name: 'Tangent',   value: Editor.Assets.VertexAttribute.Tangent },
        *       { name: 'Color',     value: Editor.Assets.VertexAttribute.Color },
        *       { name: 'Texcoord0', value: Editor.Assets.VertexAttribute.Texcoord0 },
        *       { name: 'Texcoord1', value: Editor.Assets.VertexAttribute.Texcoord1 },
        *       { name: 'Texcoord2', value: Editor.Assets.VertexAttribute.Texcoord2 },
        *       { name: 'Texcoord3', value: Editor.Assets.VertexAttribute.Texcoord3 },
        *       { name: 'BoneData',  value: Editor.Assets.VertexAttribute.BoneData },
        *     ];
        
        *     for (const attr of attrs) {
        *       console.log(`VertexAttribute.${attr.name} = ${attr.value}`);
        *     }
        * ```
        
        */
        enum VertexAttribute {
            /**
            * Vertex position coordinates in 3D space.
            */
            Position,
            /**
            * Surface normal vector for lighting calculations.
            */
            Normal,
            /**
            * Tangent vector for normal mapping.
            */
            Tangent,
            /**
            * Per-vertex color data.
            */
            Color,
            /**
            * Primary texture coordinate set.
            */
            Texcoord0,
            /**
            * Secondary texture coordinate set.
            */
            Texcoord1,
            /**
            * Tertiary texture coordinate set.
            */
            Texcoord2,
            /**
            * Quaternary texture coordinate set.
            */
            Texcoord3,
            /**
            * Skeletal animation bone indices and weights.
            */
            BoneData
        }
    
    }

}

declare namespace Editor {
    namespace Assets {
        /**
        * Options for what value is returned when a fetch falls outside the bounds of a texture.
        
        
        * @example
        * ```ts
        *     const model = this.pluginSystem.findInterface(Editor.Model.IModel) as Editor.Model.IModel;
        *     const assetManager = model.project.assetManager;
        
        *     // WrapMode controls texture coordinate behavior via Sampler
        *     const textures = assetManager.assets.filter(a => a.isOfType('Texture'));
        *     if (textures.length === 0) {
        *       console.log('No textures in project');
        *       return;
        *     }
        
        *     const texParam = new Editor.Assets.TextureParameter(textures[0].id);
        *     const sampler = texParam.sampler;
        
        *     // Repeat: tile the texture (good for tiling patterns)
        *     sampler.wrapModeU = Editor.Assets.WrapMode.Repeat;
        *     sampler.wrapModeV = Editor.Assets.WrapMode.Repeat;
        
        *     // ClampToEdge: no tiling (good for UI textures)
        *     sampler.wrapModeU = Editor.Assets.WrapMode.ClampToEdge;
        *     sampler.wrapModeV = Editor.Assets.WrapMode.ClampToEdge;
        
        *     console.log(`Sampler final: U=ClampToEdge (${sampler.wrapModeU}), V=ClampToEdge (${sampler.wrapModeV})`);
        * ```
        
        */
        enum WrapMode {
            /**
            * Texture coordinates will be clamped between 0 and 1.
            
            */
            ClampToEdge,
            /**
            * Between -1 and 1, the texture is mirrored across the 0 axis. The image is repeated outside of that range.
            
            */
            MirroredRepeat,
            /**
            * Wrap to the other side of the texture, effectively ignoring the integer part of the number to keep only the fractional part of the texture coordinate.
            
            */
            Repeat,
            /**
            * Outside the range of 0 to 1, texture coordinates return the value specified by the borderColor property.
            
            */
            ClampToBorderColor
        }
    
    }

}

declare namespace Editor {
    /**
    * Enum of spatial axes.
    
    * @example
    * ```ts
    *     const axes = [
    *       { name: 'X', value: Editor.Axis.X, desc: 'Horizontal axis (left/right)' },
    *       { name: 'Y', value: Editor.Axis.Y, desc: 'Vertical axis (up/down)' },
    *       { name: 'Z', value: Editor.Axis.Z, desc: 'Depth axis (forward/back)' },
    *     ];
    
    *     for (const axis of axes) {
    *       console.log(`Axis.${axis.name} = ${axis.value} — ${axis.desc}`);
    *     }
    * ```
    
    */
    enum Axis {
        /**
        * X-axis.
        */
        X,
        /**
        * Y-axis.
        */
        Y,
        /**
        * Z-axis.
        */
        Z
    }

}

declare namespace Editor {
    /**
    * Wraps a byte array for data serialization and deserialization.
    
    * @example
    * ```ts
    *     const bytes = new Uint8Array([72, 101, 108, 108, 111]); // "Hello"
    *     const buffer = new Editor.Buffer(bytes);
    
    *     // Round-trip: toBytes() recovers the original byte array
    *     const roundTripped = buffer.toBytes();
    *     const matches = roundTripped.every((b: number, i: number) => b === bytes[i]);
    
    *     console.log(`Buffer "${buffer.toString()}" (${roundTripped.length} bytes), round-trip match: ${matches}`);
    * ```
    
    */
    class Buffer {
        /**
        * Create a buffer from a byte array.
        */
        constructor(bytes: Uint8Array)
        
        /**
        * Return the underlying byte array.
        */
        toBytes(): Uint8Array
        
        /**
        * Return the buffer contents as a UTF-8 string.
        */
        toString(): string
        
    }

}

declare namespace Editor {
    /**
    * Container for all scene component types and related enums.
    
    * @example
    * ```ts
    *     const model = this.pluginSystem.findInterface(Editor.Model.IModel) as Editor.Model.IModel;
    *     const scene = model.project.scene;
    
    *     // Create a scene object and add components to it
    *     const obj = scene.createSceneObject('ComponentDemo');
    
    *     // Add a Camera component
    *     const cam = obj.addComponent('Camera') as Editor.Components.Camera;
    *     cam.fov = 60;
    *     console.log(`Added Camera, fov=${cam.fov}`);
    
    *     // Add a ScriptComponent
    *     const script = obj.addComponent('ScriptComponent') as Editor.Components.ScriptComponent;
    *     console.log(`Added ScriptComponent`);
    
    *     // List all components on the object
    *     for (const comp of obj.components) {
    *       console.log(`  Component: ${comp.getTypeName()}, enabled=${comp.enabled}`);
    *     }
    
    *     // Disable a component
    *     cam.enabled = false;
    *     console.log(`Camera enabled: ${cam.enabled}`);
    * ```
    
    */
    class Components {
        
        /** @hidden */
        protected constructor()
        
    }

}

