declare namespace Editor {
    namespace GaussianSplatting {
        /**
        * Enum of preset compression profiles consumed by GsafImporterSettings.compressionProfile, trading file size against visual quality.
        
        */
        enum GsCompressionProfile {
            /**
            * Smallest output file size at the lowest visual quality.
            
            */
            Tiny,
            /**
            * Small output file size with reduced visual quality.
            
            */
            Small,
            /**
            * Balanced trade-off between output file size and visual quality.
            
            */
            Balanced,
            /**
            * Larger output file size with higher visual quality.
            
            */
            Large,
            /**
            * Largest compressed output file size at the highest visual quality.
            
            */
            Ultra,
            /**
            * No lossy compression is applied; splats are stored at full precision.
            
            */
            Uncompressed,
            /**
            * Bit depths are taken from GsafImporterSettings advancedSettings fields rather than from a preset.
            
            */
            Manual
        }
    
    }

}

declare namespace Editor {
    namespace GaussianSplatting {
        /**
        * Enum selecting how splat rotation quaternions are packed when encoding a GSAF asset, consumed by GsafImporterSettings.quatPackingMethod.
        
        */
        enum GsQuatPackingMethod {
            /**
            * Stores the w, x, and y components of the quaternion and reconstructs z at runtime.
            
            */
            WXY,
            /**
            * Stores the three smallest quaternion components and reconstructs the largest at runtime.
            
            */
            SmallestThree,
            /**
            * Encodes the quaternion using its logarithmic map representation.
            
            */
            LogMap,
            /**
            * Encodes the quaternion using a Cayley transform parameterization.
            
            */
            Cayley,
            /**
            * Encodes the quaternion using a half-angle parameterization.
            
            */
            HalfAngle,
            /**
            * Encodes the quaternion using a harmonic-mean parameterization.
            
            */
            HarmonicMean,
            /**
            * Lets the importer pick the packing method that minimizes reconstruction error for the input.
            
            */
            Automatic
        }
    
    }

}

